#include <stddef.h>

/* Replace macros with immutable string objects and provide safe accessors
   to reduce risk of accidental use as format strings or unsafe copies. */
static const char VERSION_STR[] = "3.06.00";
static const char YEARS_STR[]   = "1996-2015";

/* Accessors returning const pointers (read-only). */
const char *get_version_str(void) { return VERSION_STR; }
const char *get_years_str(void)  { return YEARS_STR; }

/* Safe copy helpers: copy into a caller-provided buffer with explicit size. */
static inline void version_copy(char *dst, size_t dstlen)
{
    if (dst == NULL || dstlen == 0) return;
    /* snprintf will truncate and NUL-terminate when dstlen > 0 */
    (void)snprintf(dst, dstlen, "%s", VERSION_STR);
}

static inline void years_copy(char *dst, size_t dstlen)
{
    if (dst == NULL || dstlen == 0) return;
    (void)snprintf(dst, dstlen, "%s", YEARS_STR);
}
","explanation":"Replaced preprocessor macros with const char arrays and provided accessors and safe-copy helper functions. This prevents accidental macro redefinition or token concatenation, reduces the chance of using version/year strings directly as printf format strings, and gives callers a safe way to copy the values into fixed-size buffers."}

