{
  "file1_fix": "#ifndef __L2TP_PROT_H
#define __L2TP_PROT_H

#include <stdint.h>

#define L2TP_PORT 1701

/*
 * Provide a portable flexible-array-member macro:
 * - Use standard C99 flexible array member where available.
 * - Fall back to zero-length array for compilers that historically supported it (GCC pre-C99).
 * - For MSVC, which does not support flexible or zero-length arrays, fall back to a single-byte array
 *   to keep the header usable; callers must account for this when compiling with MSVC.
 */
#ifndef L2TP_FLEX_ARRAY_MEMBER
#  if defined(__STDC_VERSION__) && __STDC_VERSION__ >= 199901L
#    define L2TP_FLEX_ARRAY_MEMBER(type, name) type name[]
#  elif defined(_MSC_VER)
#    define L2TP_FLEX_ARRAY_MEMBER(type, name) type name[1]
#  else
#    define L2TP_FLEX_ARRAY_MEMBER(type, name) type name[0]
#  endif
#endif

/*
 * Use an explicit 16-bit 'flags' field instead of implementation-defined bitfields
 * to avoid ambiguity in bit ordering across compilers/architectures.
 * Accessor macros are provided to extract the standard L2TP flag bits and version.
 * NOTE: flags are received on the wire in network byte order; callers should
 * convert to host order (ntohs) before using these macros when parsing raw packets.
 */
struct l2tp_hdr_t
{
    uint16_t flags;   /* raw 16-bit flags/version field (network byte order on-the-wire) */
    uint16_t length;
    union {
        struct {
            uint16_t tid;
            uint16_t sid;
        };
        uint32_t cid;
    };
    uint16_t Ns;
    uint16_t Nr;
} __attribute__((packed));

/* Accessor macros assume 'flags' is in host byte order. Callers parsing network data
 * should call ntohs(hdr->flags) first. These reproduce the originally-intended bit layout. */
#define L2TP_T(hdr)    (((hdr)->flags >> 15) & 0x1)
#define L2TP_L(hdr)    (((hdr)->flags >> 14) & 0x1)
#define L2TP_S(hdr)    (((hdr)->flags >> 10) & 0x1)
#define L2TP_O(hdr)    (((hdr)->flags >> 8)  & 0x1)
#define L2TP_VER(hdr)  ((hdr)->flags & 0x0f)

struct l2tp_avp_t
{
    uint16_t length:10;
    uint16_t reserved:4;
    uint16_t H:1;
    uint16_t M:1;
    uint16_t vendor;
    uint16_t type;
    L2TP_FLEX_ARRAY_MEMBER(uint8_t, val);
} __attribute__((packed));

struct l2tp_avp_result_code
{
    uint16_t result_code;
    uint16_t error_code;
    L2TP_FLEX_ARRAY_MEMBER(char, error_msg);
} __attribute__((packed));

#endif
",
  "explanation": "Replaced implementation-defined bitfields in l2tp_hdr_t with an explicit uint16_t 'flags' field and provided accessor macros to avoid compiler-dependent bit ordering. Added a portable L2TP_FLEX_ARRAY_MEMBER macro to select a compatible flexible/zero-length array form depending on compiler, preserving intent while improving portability and safety."
}

