import secrets
import fnmatch
from typing import Any, Dict, Optional, Tuple
from urllib.parse import urlparse

from django.conf import settings
from django.http import HttpRequest, JsonResponse
from django.views.decorators.csrf import csrf_exempt
from rest_framework import status
from sentry_sdk import capture_exception
from statshog.defaults.django import statsd

from posthog.api.utils import get_token
from posthog.exceptions import RequestParsingError, generate_exception_response
from posthog.models import Team, User
from posthog.models.feature_flag import get_overridden_feature_flags
from posthog.utils import cors_response, load_data_from_request

from .utils import get_project_id


def on_permitted_domain(team: Team, request: HttpRequest) -> bool:
    permitted_domains = ["127.0.0.1", "localhost"]

    for url in team.app_urls:
        hostname = parse_domain(url)
        if hostname:
            permitted_domains.append(hostname)

    origin = parse_domain(request.headers.get("Origin"))
    referer = parse_domain(request.headers.get("Referer"))

    # Limit lengths to avoid pathological inputs
    max_len = 255
    if origin and len(origin) > max_len:
        origin = None
    if referer and len(referer) > max_len:
        referer = None

    for permitted_domain in permitted_domains:
        if not isinstance(permitted_domain, str) or len(permitted_domain) == 0:
            continue

        # use fnmatch for safe wildcard matching and ensure case-insensitive compare
        permitted_domain_norm = permitted_domain.lower()

        if "*" in permitted_domain_norm:
            try:
                if origin and fnmatch.fnmatch(origin, permitted_domain_norm):
                    return True
                if referer and fnmatch.fnmatch(referer, permitted_domain_norm):
                    return True
            except Exception:
                # In case of unexpected pattern issues, skip this permitted_domain
                continue
        else:
            if origin == permitted_domain_norm or referer == permitted_domain_norm:
                return True
    return False


def decide_editor_params(request: HttpRequest) -> Tuple[Dict[str, Any], bool]:
    if request.user.is_anonymous:
        return {}, False

    team = request.user.team
    if team and on_permitted_domain(team, request):
        response: Dict[str, Any] = {"isAuthenticated": True}
        editor_params = {}

        if request.user.toolbar_mode != "disabled":
            editor_params["toolbarVersion"] = "toolbar"

        if settings.JS_URL:
            editor_params["jsURL"] = settings.JS_URL

        response["editorParams"] = editor_params
        return response, not request.user.temporary_token
    else:
        return {}, False


def parse_domain(url: Any) -> Optional[str]:
    # Safely parse hostnames from possibly malformed or missing URLs/headers.
    # Returns a lower-cased hostname (without port) or None.
    if not url or not isinstance(url, str):
        return None

    url = url.strip()
    if not url:
        return None

    # Some clients send the literal string 'null' for Origin; treat as absent
    if url.lower() == "null":
        return None

    # Try parsing directly; if no hostname, try prepending a scheme to handle scheme-less values
    parsed = urlparse(url)
    hostname = parsed.hostname
    if not hostname:
        try:
            parsed = urlparse("https://" + url)
            hostname = parsed.hostname
        except Exception:
            return None

    if not hostname:
        return None

    # Normalize to lower-case and strip surrounding whitespace
    hostname = hostname.strip().lower()

    # Basic sanity check: hostname should not be overly long
    if len(hostname) > 255:
        return None

    return hostname


