    if (!msg) return;
    char name[SU_ADDRSIZE] = "";
    su_sockaddr_t const *su = msg_addr(msg);
    if (!su) return;
    if (su_inet_ntop(su->su_family, SU_ADDR(su), name, sizeof(name)) != NULL) {
