#include <limits.h>

int
snmp_clone_mem(void **dstPtr, const void *srcPtr, unsigned len)
{
    /* Validate destination pointer first to avoid dereferencing NULL. */
    if (dstPtr == NULL)
        return 1;

    *dstPtr = NULL;
    if (srcPtr) {
        /*
         * Prevent overflow when computing (size_t)len + 1 for malloc.
         * Promote 'len' to size_t and ensure there's room for the
         * additional NUL terminator byte.
         */
        size_t ulen = (size_t) len;
        if (ulen > SIZE_MAX - 1)
            return 1;

        size_t alloc_size = ulen + 1;
        *dstPtr = malloc(alloc_size);
        if (!*dstPtr) {
            return 1;
        }

        memmove(*dstPtr, srcPtr, ulen);
        /*
         * this is for those routines that expect 0-terminated strings!!!
         * someone should rather have called strdup
         */
        ((char *) *dstPtr)[ulen] = '\0';
    }
    return 0;
}
