xsnprintf_func (char *str, int n, const char *fmt, ...)
{
  va_list a;
  int ret;

  /* Defend against invalid buffer size. Preserve caller-visible
   * behavior of producing a NUL-terminated string when possible, and
   * return the vsnprintf-style result (negative on encoding error,
   * non-negative number of bytes that would have been written).
   */
  if (n <= 0) {
    /* No room for output or NUL; consume args but return error. */
    va_start(a, fmt);
    (void)fmt; /* keep compiler happy if vsnprintf_func unavailable */
    va_end(a);
    return -1;
  }

  va_start (a, fmt);
  ret = vsnprintf_func (str, n, fmt, a);
  va_end (a);

  if (ret < 0)
    {
      /* Encoding error: ensure an empty, NUL-terminated string. */
      str[0] = '\0';
      return -1;
    }

  if (ret >= n)
    {
      /* Output was truncated; make sure buffer is NUL-terminated.  The
       * C99/C11/posix guarantee is that vsnprintf writes at most n-1
       * characters plus the terminating NUL when n > 0, but being
       * defensive here protects against non-conforming replacements
       * of vsnprintf_func. */
      str[n-1] = '\0';
    }

  return ret;
}
