            pasteCatcher = document.createElement('div');
            pasteCatcher.id = 'screenshot-pastezone';
            pasteCatcher.contentEditable = true;
            pasteCatcher.style.opacity = '0';
            pasteCatcher.style.position = 'fixed';
            pasteCatcher.style.top = '0';
            pasteCatcher.style.right = '0';
            pasteCatcher.style.width = '1px';
            pasteCatcher.style.height = '1px';
            pasteCatcher.style.overflow = 'hidden';
            pasteCatcher.style.zIndex = '-9999';
            pasteCatcher.setAttribute('aria-hidden', 'true');

            document.body.insertBefore(pasteCatcher, document.body.firstChild);

            // Focus so pasted content goes into this element
            try { pasteCatcher.focus(); } catch (e) {}

            // Set the focus when clicked anywhere in the document
            document.addEventListener('click', setFocus);

            // Set the focus when clicked in screenshot dropzone (if present)
            var zone = document.getElementById('screenshot-zone');
            if (zone) {
                zoneClickHandler = setFocus;
                zone.addEventListener('click', zoneClickHandler);
            }
        }

        // Listen for paste events
        window.addEventListener('paste', onPaste, false);
    }

    function destroy() {
        if (pasteCatcher) {
            if (pasteCatcher.parentNode) {
                pasteCatcher.parentNode.removeChild(pasteCatcher);
            }
            pasteCatcher = null;
        }

        // Remove global listeners that initialize added
        document.removeEventListener('click', setFocus);
        if (zoneClickHandler) {
            var zone = document.getElementById('screenshot-zone');
            if (zone) {
                zone.removeEventListener('click', zoneClickHandler);
            }
            zoneClickHandler = null;
        }

        window.removeEventListener('paste', onPaste, false);
    }

    function setFocus() {
        if (pasteCatcher !== null) {
            try { pasteCatcher.focus(); } catch (e) {}
        }
    }

    function checkInput() {
        if (!pasteCatcher) { return; }

        var child = pasteCatcher.childNodes[0];

        if (child) {
            // If the user pastes an image, the src attribute
            // will represent the image as a base64 encoded string.
            if (child.tagName === 'IMG') {
                var src = child.src || '';
                // Validate that src is a data URL with an image mime type
                if (typeof src === 'string' && src.indexOf('data:') === 0) {
                    createImage(src);
                }
            }
        }

        // Clear the paste catcher safely
        try { pasteCatcher.innerHTML = ''; } catch (e) { /* ignore */ }
    }

    function createImage(blob) {
        // blob is expected to be a data URL (string) like "data:image/png;base64,...."
        if (typeof blob !== 'string') { return; }

        // Basic validation: must start with data: and be an image mime type
        if (blob.indexOf('data:') !== 0) { return; }

        var metaEnd = blob.indexOf(';');
        if (metaEnd === -1) { return; }

        var mime = blob.substring(5, metaEnd).toLowerCase();
        if (mime.indexOf('image/') !== 0) { return; }

        var base64Index = blob.indexOf('base64,');
        if (base64Index === -1) { return; }

        var base64Data = blob.substring(base64Index + 7);

        // Limit base64 size to avoid memory/DoS issues (e.g. ~7MB base64 ~= 5MB binary)
        var MAX_BASE64_LENGTH = 7 * 1024 * 1024;
        if (base64Data.length > MAX_BASE64_LENGTH) { return; }

        var pastedImage = new Image();
        pastedImage.src = blob;

        // Send the image content to the form variable
        pastedImage.onload = function () {
            try {
                if (!inputElement) { return; }

                // Extract the base64 portion again and set the hidden input value
                var sourceSplit = blob.split('base64,');
                if (sourceSplit.length > 1) {
                    inputElement.value = sourceSplit[1];
                }
            } catch (e) {
                // Ignore errors writing to the input
            }
        };

        var zone = document.getElementById('screenshot-zone');
        if (zone) {
            // Clear existing content without using innerHTML with untrusted strings
            while (zone.firstChild) { zone.removeChild(zone.firstChild); }
            zone.className = (zone.className || '') + ' screenshot-pasted';
            zone.appendChild(pastedImage);
        }

        // Reinitialize paste catcher to accept more pastes (clean teardown)
        destroy();
        initialize();
    }

    KB.on('modal.close', function () {
        destroy();
    });

    this.render = function () {
        inputElement = KB.dom('input')
            .attr('type', 'hidden')
            .attr('name', 'screenshot')
            .build();

        containerElement.appendChild(inputElement);
        initialize();
    };
});",
